package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithEscape_char() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char escapeChar = '\\';

        CSVFormat resultFormat = baseFormat.withEscape(escapeChar);

        assertNotNull(resultFormat);
        assertEquals(Character.valueOf(escapeChar), resultFormat.getEscapeCharacter());
        // Original format is unchanged (immutability)
        assertNull(baseFormat.getEscapeCharacter());
    }

    @Test
    void testWithEscape_char_differentEscape() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        char escapeChar = '"';

        CSVFormat resultFormat = baseFormat.withEscape(escapeChar);

        assertNotNull(resultFormat);
        assertEquals(Character.valueOf(escapeChar), resultFormat.getEscapeCharacter());
        assertNull(baseFormat.getEscapeCharacter());
    }

    @Test
    void testWithEscape_char_sameEscape() {
        CSVFormat baseFormat = CSVFormat.DEFAULT.withEscape((Character) null);
        char escapeChar = ',';

        CSVFormat resultFormat = baseFormat.withEscape(escapeChar);

        assertNotNull(resultFormat);
        assertEquals(Character.valueOf(escapeChar), resultFormat.getEscapeCharacter());
        assertNull(baseFormat.getEscapeCharacter());
    }
}
